-						w.Header().Set("Access-Control-Allow-Methods", strings.Join(allMethods, ","))
-					}
-				}
+			if err == nil && len(allMethods) > 0 {
+				w.Header().Set("Access-Control-Allow-Methods", strings.Join(allMethods, ","))
 			}

 			next.ServeHTTP(w, req)
